inputs.javascriptFunction:
const { MongoClient } = require('mongodb');

const url = 'mongodb://127.0.0.1:27017';
const client = new MongoClient(url);

try {
    await client.connect();

    const db = client.db('my_portfolio');
    const collection = db.collection('portfolio_database');

    const rawData = await collection.find({}).toArray();

    const docs = rawData.map((item) => {
        const { _id, category, ...rest } = item;

        let formattedText = "";

        switch(category){

            case "personal":
                formattedText = `Khushboo Gupta is a ${rest.role} based in ${rest.location}. She can be contacted via email ${rest.email}.`;
                break;

            case "summary":
                formattedText = `Professional Summary: ${rest.profile}`;
                break;

            case "skills":
                formattedText = `Khushboo's technical skills include ${rest.technical?.join(", ")}. Her soft skills include ${rest.soft?.join(", ")}.`;
                break;

            case "experience":
                formattedText = `She worked at ${rest.company} as a ${rest.role} during ${rest.duration}. Key contributions: ${rest.work?.join(" ")}`;
                break;

            case "project":
                formattedText = `Project: ${rest.name}. Type: ${rest.type}. Built using ${rest.tech?.join(", ")}. Impact: ${rest.impact}. Description: ${rest.description}`;
                break;

            case "education":
                formattedText = `She completed ${rest.degree} from ${rest.university} with a score of ${rest.score} during ${rest.year}.`;
                break;

            case "certification":
                formattedText = `Certification: ${rest.name} from ${rest.provider}.`;
                break;

            case "career_vision":
                formattedText = `Her long-term goal is to ${rest.long_term_goal}. She believes ${rest.belief}. She focuses on ${rest.future_focus?.join(", ")}.`;
                break;

            case "philosophy":
                formattedText = `Her work philosophy: ${rest.approach}. She follows this approach: ${rest.work_style?.join(", ")}.`;
                break;

            case "learning":
                formattedText = `She continuously improves herself by focusing on ${rest.focus_areas?.join(", ")}.`;
                break;

            case "identity":
                formattedText = `She enjoys solving real-world problems and aims to ${rest.motivation}.`;
                break;

            case "aspiration":
                formattedText = `Her future aspiration is to become ${rest.future_role} and contribute through ${rest.long_term_learning_direction?.join(", ")}.`;
                break;

            case "mission":
                formattedText = `Her personal mission is: ${rest.vision}`;
                break;

            case "motivation":
                formattedText = `She chose Data Science because ${rest.why_data_science}.`;
                break;

            default:
                formattedText = JSON.stringify(rest);
        }

        return {
            pageContent: formattedText,
            metadata: {
                mongo_id: _id.toString(),
                category: category,
                source: "my_portfolio"
            }
        }
    });

    if (!docs.length) {
        return [{ pageContent: "No portfolio data found", metadata: {} }];
    }

    return docs;

} catch (error) {
    return [{ 
        pageContent: `Error connecting: ${error.message}`, 
        metadata: { error: true } 
    }];
} finally {
    await client.close();
}

